import { Pagination, PaginationProps } from 'antd';
import React, { memo } from 'react';
import { FC } from 'react';

const showTotal: PaginationProps['showTotal'] = (total, range) =>
    `第 ${range[0]}-${range[1]} 条/总共 ${total} 条`;

export interface SptTablePaginationProps extends PaginationProps {}

const SptPagination: FC<SptTablePaginationProps> = ({ current, total, pageSize, onChange }) => {
    return (
        <div className="spt-table-pagination-wrap">
            <Pagination
                className="spt-table-pagination"
                current={current}
                total={total}
                showTotal={showTotal}
                pageSize={pageSize}
                onChange={onChange}
            />
        </div>
    );
};

export default memo(SptPagination);